# Простейший алгоритм: найти максимум в списке
def find_max(numbers):
    current_max = numbers[0]
    for number in numbers:
        if number > current_max:
            current_max = number
    return current_max

print(find_max([3, 7, 2, 9, 1]))  # 9

# Медленный способ: проверяем каждый элемент
def slow_search(lst, target):
    for item in lst:
        if item == target:
            return True
    return False

# Быстрый способ: бинарный поиск (список должен быть отсортирован)
def fast_search(sorted_lst, target):
    low, high = 0, len(sorted_lst) - 1
    while low <= high:
        mid = (low + high) // 2
        if sorted_lst[mid] == target:
            return True
        elif sorted_lst[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return False

# O(n) — линейное время
def linear_search(lst, target):
    for i, item in enumerate(lst):
        if item == target:
            return i
    return -1

# В худшем случае проверим каждый элемент
result = linear_search([4, 2, 7, 1, 9], 9)  # 5 проверок
print(result)  # 4 (индекс элемента 9)

# Trade-off: время vs память

# Медленный вариант — O(n) времени, O(1) памяти
def has_duplicates_slow(lst):
    for i in range(len(lst)):
        for j in range(i + 1, len(lst)):
            if lst[i] == lst[j]:
                return True
    return False

# Быстрый вариант — O(n) времени, O(n) памяти
def has_duplicates_fast(lst):
    seen = set()  # Доп. память для множества
    for item in lst:
        if item in seen:
            return True
        seen.add(item)
    return False

