# Практический пример: проверка скобок
def check_brackets(expression):
    stack = []
    pairs = {")": "(", "]": "[", "}": "{"}

    for char in expression:
        if char in "([{":
            stack.append(char)  # Открывающая — кладём в стек
        elif char in ")]}":
            if not stack or stack[-1] != pairs[char]:
                return False  # Нет пары!
            stack.pop()  # Нашли пару — убираем

    return len(stack) == 0  # Стек должен быть пуст

print(check_brackets("(a + b) * [c - d]"))  # True
print(check_brackets("((a + b)"))            # False
print(check_brackets("{[}]"))                # False

