# Простое возведение в степень — O(n)
def power_simple(base, exp):
    if exp == 0:
        return 1
    return base * power_simple(base, exp - 1)

# Быстрое возведение в степень — O(log n)
def power_fast(base, exp):
    if exp == 0:
        return 1
    if exp % 2 == 0:  # Чётная степень
        half = power_fast(base, exp // 2)
        return half * half
    else:  # Нечётная степень
        return base * power_fast(base, exp - 1)

print(power_simple(2, 10))  # 1024
print(power_fast(2, 10))    # 1024

# Упражнение: длина списка рекурсивно
def recursive_len(lst):
    if lst == []:
        return 0
    return 1 + recursive_len(lst[1:])

# Упражнение: максимум списка рекурсивно
def recursive_max(lst):
    if len(lst) == 1:
        return lst[0]
    rest_max = recursive_max(lst[1:])
    return lst[0] if lst[0] > rest_max else rest_max

print(recursive_len([5, 3, 8, 1]))  # 4
print(recursive_max([5, 3, 8, 1]))  # 8

# Наивная рекурсивная реализация
def fib(n):
    if n <= 0:
        return 0
    if n == 1:
        return 1
    return fib(n - 1) + fib(n - 2)

