# Мемоизация вручную
def fib_memo(n, cache={}):
    if n in cache:
        return cache[n]  # Уже считали — берём из блокнота
    if n <= 0:
        return 0
    if n == 1:
        return 1
    cache[n] = fib_memo(n - 1, cache) + fib_memo(n - 2, cache)
    return cache[n]

