# Python имеет встроенный декоратор для мемоизации
from functools import lru_cache

@lru_cache(maxsize=None)
def fib_cached(n):
    if n <= 0:
        return 0
    if n == 1:
        return 1
    return fib_cached(n - 1) + fib_cached(n - 2)

print(fib_cached(100))  # 354224848179261915075

# Итеративное решение — O(n) времени, O(1) памяти
def fib_iterative(n):
    if n <= 0:
        return 0
    a, b = 0, 1
    for _ in range(n - 1):
        a, b = b, a + b
    return b

print(fib_iterative(10))   # 55
print(fib_iterative(100))  # 354224848179261915075

# Числа Трибоначчи: каждое = сумма трёх предыдущих
@lru_cache(maxsize=None)
def tribonacci(n):
    if n <= 0: return 0
    if n <= 2: return 1
    return tribonacci(n-1) + tribonacci(n-2) + tribonacci(n-3)

# 0, 1, 1, 2, 4, 7, 13, 24, 44...
print([tribonacci(i) for i in range(10)])

# Числа Каталана: C(n) = сумма C(i)*C(n-1-i) для i от 0 до n-1
@lru_cache(maxsize=None)
def catalan(n):
    if n <= 1: return 1
    return sum(catalan(i) * catalan(n-1-i) for i in range(n))

# 1, 1, 2, 5, 14, 42, 132...
print([catalan(i) for i in range(8)])

# НЕ хвостовая рекурсия — после вызова ещё нужно умножить
def factorial(n):
    if n <= 1:
        return 1
    return n * factorial(n - 1)  # Ещё надо умножить на n!

# Хвостовая рекурсия — вызов последний, ничего после
def factorial_tail(n, accumulator=1):
    if n <= 1:
        return accumulator
    return factorial_tail(n - 1, n * accumulator)  # Всё готово!

print(factorial(5))            # 120
print(factorial_tail(5))       # 120

# Преобразование: сумма списка

# Обычная рекурсия
def sum_list(lst):
    if not lst:
        return 0
    return lst[0] + sum_list(lst[1:])  # Ещё нужно сложить!

# Хвостовая рекурсия (с аккумулятором)
def sum_list_tail(lst, acc=0):
    if not lst:
        return acc
    return sum_list_tail(lst[1:], acc + lst[0])  # Сумма уже посчитана!

# Преобразование: разворот строки
def reverse_tail(s, acc=""):
    if not s:
        return acc
    return reverse_tail(s[1:], s[0] + acc)

print(sum_list_tail([1, 2, 3, 4, 5]))  # 15
print(reverse_tail("привет"))           # "тевирп"

