# Ещё пример: найти максимум методом «дели и властвуй»
def max_dac(arr):
    if len(arr) == 1:
        return arr[0]
    mid = len(arr) // 2
    left_max = max_dac(arr[:mid])
    right_max = max_dac(arr[mid:])
    return left_max if left_max > right_max else right_max

print(max_dac([3, 7, 2, 9, 1, 8]))  # 9

# Сумма массива методом «дели и властвуй»
def sum_dac(arr):
    if len(arr) == 0:
        return 0
    if len(arr) == 1:
        return arr[0]
    mid = len(arr) // 2
    return sum_dac(arr[:mid]) + sum_dac(arr[mid:])

print(sum_dac([1, 2, 3, 4, 5]))  # 15

# Без сортировки: ищем элемент перебором — O(n)
def linear_search(arr, target):
    for i in range(len(arr)):
        if arr[i] == target:
            return i
    return -1

# С сортировкой: бинарный поиск — O(log n)
def binary_search(arr, target):
    lo, hi = 0, len(arr) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1

def bubble_sort(arr):
    n = len(arr)
    for i in range(n):
        swapped = False
        for j in range(n - 1 - i):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
                swapped = True
        if not swapped:
            break  # массив уже отсортирован
    return arr

print(bubble_sort([5, 3, 8, 1, 2]))  # [1, 2, 3, 5, 8]

