from bisect import bisect_left

def find_closest(arr, target):
    pos = bisect_left(arr, target)
    candidates = []
    if pos < len(arr):
        candidates.append(arr[pos])
    if pos > 0:
        candidates.append(arr[pos - 1])
    return min(candidates, key=lambda x: abs(x - target))

