def search(node, target):
    """Поиск значения в бинарном дереве (обход всех узлов)"""
    if node is None:
        return False
    if node.value == target:
        return True
    # Ищем в левом поддереве, потом в правом
    return search(node.left, target) or search(node.right, target)

