def dfs_iterative(root):
    """Итеративный DFS (pre-order) с явным стеком"""
    if root is None:
        return []

    result = []
    stack = [root]

    while stack:
        node = stack.pop()         # Достаём из вершины стека
        result.append(node.value)

        # Правый добавляем первым, чтобы левый обработался раньше
        if node.right:
            stack.append(node.right)
        if node.left:
            stack.append(node.left)

    return result

