def update(arr, tree, node, start, end, idx, val):
    """Обновить arr[idx] = val"""
    if start == end:
        arr[idx] = val
        tree[node] = val
    else:
        mid = (start + end) // 2
        if idx <= mid:
            update(arr, tree, 2 * node + 1, start, mid, idx, val)
        else:
            update(arr, tree, 2 * node + 2, mid + 1, end, idx, val)
        tree[node] = tree[2 * node + 1] + tree[2 * node + 2]

