class FenwickTree:
    def __init__(self, n):
        self.n = n
        self.tree = [0] * (n + 1)  # 1-индексация

    def update(self, i, delta):
        """Прибавить delta к элементу i"""
        while i <= self.n:
            self.tree[i] += delta
            i += i & (-i)

    def prefix_sum(self, i):
        """Сумма элементов [1..i]"""
        total = 0
        while i > 0:
            total += self.tree[i]
            i -= i & (-i)
        return total

    def range_sum(self, l, r):
        """Сумма элементов [l..r]"""
        return self.prefix_sum(r) - self.prefix_sum(l - 1)

    @classmethod
    def from_array(cls, arr):
        """Построить дерево из массива (0-индексация -> 1-индексация)"""
        ft = cls(len(arr))
        for i, val in enumerate(arr):
            ft.update(i + 1, val)
        return ft

# Использование
