from collections import defaultdict

def build_adj_list(n, edges, directed=False):
    """Строим список смежности из списка рёбер."""
    graph = defaultdict(list)
    for u, v in edges:
        graph[u].append(v)
        if not directed:
            graph[v].append(u)
    return graph

def build_adj_matrix(n, edges, directed=False):
    """Строим матрицу смежности n×n."""
    matrix = [[0] * n for _ in range(n)]
    for u, v in edges:
        matrix[u][v] = 1
        if not directed:
            matrix[v][u] = 1
    return matrix

