    print(row)

def matrix_to_adj_list(matrix):
    """Матрица смежности -> список смежности."""
    n = len(matrix)
    adj = defaultdict(list)
    for i in range(n):
        for j in range(n):
            if matrix[i][j] != 0:
                adj[i].append(j)
    return adj

def adj_list_to_matrix(adj, n):
    """Список смежности -> матрица смежности."""
    matrix = [[0] * n for _ in range(n)]
    for u in adj:
        for v in adj[u]:
            matrix[u][v] = 1
    return matrix

