def find_components(graph):
    """Находим все компоненты связности."""
    visited = set()
    components = []

    for vertex in graph:
        if vertex not in visited:
            component = []
            stack = [vertex]
            while stack:
                v = stack.pop()
                if v not in visited:
                    visited.add(v)
                    component.append(v)
                    for neighbor in graph[v]:
                        if neighbor not in visited:
                            stack.append(neighbor)
            components.append(component)

    return components

