def has_cycle(graph, all_vertices):
    """Проверка наличия цикла в направленном графе."""
    WHITE, GRAY, BLACK = 0, 1, 2
    color = {v: WHITE for v in all_vertices}

    def dfs(v):
        color[v] = GRAY  # вершина в обработке
        for neighbor in graph.get(v, []):
            if color[neighbor] == GRAY:  # нашли цикл!
