from collections import defaultdict

def kosaraju(graph, all_vertices):
    """Алгоритм Косарайю: находит компоненты сильной связности."""
    # Шаг 1: DFS и запись порядка завершения
    visited = set()
    finish_order = []

    def dfs1(v):
        visited.add(v)
        for u in graph.get(v, []):
            if u not in visited:
                dfs1(u)
        finish_order.append(v)

    for v in all_vertices:
        if v not in visited:
            dfs1(v)

    # Шаг 2: Транспонирование графа
    transposed = defaultdict(list)
    for u in graph:
        for v in graph[u]:
            transposed[v].append(u)

    # Шаг 3: DFS по транспонированному графу
    visited.clear()
    components = []

    def dfs2(v, component):
        visited.add(v)
        component.append(v)
        for u in transposed.get(v, []):
            if u not in visited:
                dfs2(u, component)

    for v in reversed(finish_order):
        if v not in visited:
            comp = []
            dfs2(v, comp)
            components.append(comp)

    return components

