import math

def floyd_warshall(n, edges):
    """Floyd-Warshall: кратчайшие пути между всеми парами."""
    INF = math.inf
    dist = [[INF] * n for _ in range(n)]
    nxt = [[None] * n for _ in range(n)]  # для восстановления пути

    for i in range(n):
        dist[i][i] = 0

    for u, v, w in edges:
        dist[u][v] = w
        nxt[u][v] = v

    # Тройной цикл — сердце алгоритма
    for k in range(n):
        for i in range(n):
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]
                    nxt[i][j] = nxt[i][k]

    return dist, nxt

# 4 города: 0, 1, 2, 3
edges = [
    (0, 1, 3), (0, 2, 6),
    (1, 2, 2), (1, 3, 1),
    (2, 3, 4), (3, 0, 7)
]

dist, nxt = floyd_warshall(4, edges)

print("Матрица кратчайших расстояний:")
for row in dist:
    print([x if x != math.inf else '∞' for x in row])

