# Наивный рекурсивный Фибоначчи — МЕДЛЕННО!
def fib_naive(n):
    if n <= 1:
        return n
    return fib_naive(n - 1) + fib_naive(n - 2)

# fib_naive(40) будет считаться ОЧЕНЬ долго,
# потому что одни и те же подзадачи решаются миллионы раз

# Сверху вниз: рекурсия + мемоизация
def fib_top_down(n, memo={}):
    if n <= 1:
        return n
    if n not in memo:
        memo[n] = fib_top_down(n - 1, memo) + fib_top_down(n - 2, memo)
    return memo[n]

print(fib_top_down(40))  # Мгновенно!

# Снизу вверх: заполняем таблицу итеративно
def fib_bottom_up(n):
    if n <= 1:
        return n
    dp = [0] * (n + 1)
    dp[1] = 1
    for i in range(2, n + 1):
        dp[i] = dp[i - 1] + dp[i - 2]
    return dp[n]

print(fib_bottom_up(40))  # Тоже мгновенно!

