from collections import deque

def longest_path_dag(adj, n):
    in_deg = [0] * n
    for u in range(n):
        for v in adj[u]:
            in_deg[v] += 1

    queue = deque()
    dp = [0] * n
    for v in range(n):
        if in_deg[v] == 0:
            queue.append(v)

    while queue:
        u = queue.popleft()
        for v in adj[u]:
            dp[v] = max(dp[v], dp[u] + 1)
            in_deg[v] -= 1
            if in_deg[v] == 0:
                queue.append(v)

    return max(dp)

