class DSU:
    def __init__(self, n):
        self.parent = list(range(n))  # Каждый сам себе корень
        self.rank = [0] * n

    def find(self, x):
        # Сжатие путей: перенаправляем прямо к корню
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return False  # Уже в одном множестве
        # Объединение по рангу: меньшее дерево под большее
        if self.rank[rx] < self.rank[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        if self.rank[rx] == self.rank[ry]:
            self.rank[rx] += 1
        return True

    def connected(self, x, y):
        return self.find(x) == self.find(y)

