def mat_mult(A, B, mod=None):
    n = len(A)
    m = len(B[0])
    p = len(B)
    C = [[0] * m for _ in range(n)]
    for i in range(n):
        for j in range(m):
            for k in range(p):
                C[i][j] += A[i][k] * B[k][j]
            if mod:
                C[i][j] %= mod
    return C

A = [[1, 2], [3, 4]]
B = [[5, 6], [7, 8]]
