# f(n) = 2*f(n-1) + 3*f(n-2), f(0) = 0, f(1) = 1
def linear_recurrence(n, mod=10**9 + 7):
    if n == 0:
        return 0
    if n == 1:
        return 1
    M = [[2, 3], [1, 0]]  # Матрица-компаньон
    result = mat_pow(M, n - 1, mod)
    # result × [f(1), f(0)]^T = [f(n), f(n-1)]^T
    return (result[0][0] * 1 + result[0][1] * 0) % mod

# Проверка: f(2)=2, f(3)=7, f(4)=23, f(5)=67
for i in range(6):
    print(f"f({i}) = {linear_recurrence(i)}")

