        if idx == -1:
            break
        count += 1
        start = idx + 1
    return count

def solution(s):
    if not s:
        return ""
    rev = s[::-1]
    combined = s + "#" + rev
    n = len(combined)
    lps = [0] * n
    for i in range(1, n):
        j = lps[i - 1]
        while j > 0 and combined[i] != combined[j]:
            j = lps[j - 1]
        if combined[i] == combined[j]:
            j += 1
        lps[i] = j
    return rev[:len(s) - lps[-1]] + s

def solution(nums, queries):
    import math
    n = len(nums)
    block = int(math.sqrt(n)) + 1
    blocks = [0] * (n // block + 2)
    for i in range(n):
        blocks[i // block] += nums[i]
    result = []
    for q in queries:
        if q[0] == 0:
            l, r = q[1], q[2]
            s = 0
            while l <= r:
                if l % block == 0 and l + block - 1 <= r:
                    s += blocks[l // block]
                    l += block
                else:
                    s += nums[l]
                    l += 1
            result.append(s)
        elif q[0] == 1:
            idx, val = q[1], q[2]
            blocks[idx // block] += val - nums[idx]
            nums[idx] = val
    return result

def solution(nums, queries):
    import math
    n = len(nums)
    block = int(math.sqrt(n)) + 1
    num_blocks = n // block + 2
    blocks = [float('inf')] * num_blocks
    for i in range(n):
        blocks[i // block] = min(blocks[i // block], nums[i])
    def rebuild(b):
        start = b * block
        end = min(start + block, n)
        blocks[b] = float('inf')
        for i in range(start, end):
            blocks[b] = min(blocks[b], nums[i])
    result = []
    for q in queries:
        if q[0] == 0:
            l, r = q[1], q[2]
            ans = float('inf')
            while l <= r:
                if l % block == 0 and l + block - 1 <= r:
                    ans = min(ans, blocks[l // block])
                    l += block
                else:
                    ans = min(ans, nums[l])
                    l += 1
            result.append(ans)
        elif q[0] == 1:
            idx, val = q[1], q[2]
            nums[idx] = val
            rebuild(idx // block)
    return result

def solution(n, m, edges):
    adj = [[] for _ in range(n)]
    for u, v in edges:
        adj[u].append(v)
    match = [-1] * m
    def dfs(u, visited):
        for v in adj[u]:
            if v not in visited:
                visited.add(v)
                if match[v] == -1 or dfs(match[v], visited):
                    match[v] = u
                    return True
        return False
    result = 0
    for u in range(n):
        if dfs(u, set()):
            result += 1
    return result

def solution(n, edges, source, sink):
    from collections import defaultdict, deque
    graph = defaultdict(lambda: defaultdict(int))
    for u, v, c in edges:
        graph[u][v] += c
    def bfs():
        parent = {source: None}
        visited = {source}
        queue = deque([source])
        while queue:
            u = queue.popleft()
            for v in graph[u]:
                if v not in visited and graph[u][v] > 0:
                    visited.add(v)
                    parent[v] = u
                    if v == sink:
                        return parent
                    queue.append(v)
        return None
    max_flow = 0
    while True:
        parent = bfs()
        if parent is None or sink not in parent:
            break
        path_flow = float('inf')
        v = sink
        while parent[v] is not None:
            u = parent[v]
            path_flow = min(path_flow, graph[u][v])
            v = u
        v = sink
        while parent[v] is not None:
            u = parent[v]
            graph[u][v] -= path_flow
            graph[v][u] += path_flow
            v = u
        max_flow += path_flow
    return max_flow

def solution(n):
    if n <= 1:
        return n
    def mat_mult(A, B):
        return [
            [A[0][0]*B[0][0]+A[0][1]*B[1][0], A[0][0]*B[0][1]+A[0][1]*B[1][1]],
            [A[1][0]*B[0][0]+A[1][1]*B[1][0], A[1][0]*B[0][1]+A[1][1]*B[1][1]]
        ]
    def mat_pow(M, p):
        result = [[1,0],[0,1]]
        while p:
            if p % 2:
                result = mat_mult(result, M)
            M = mat_mult(M, M)
            p //= 2
        return result
    M = [[1,1],[1,0]]
    return mat_pow(M, n)[0][1]

def solution(adj, k, u, v):
    n = len(adj)
    def mat_mult(A, B):
        C = [[0]*n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                for l in range(n):
                    C[i][j] += A[i][l] * B[l][j]
        return C
    def mat_pow(M, p):
        result = [[1 if i==j else 0 for j in range(n)] for i in range(n)]
        while p:
            if p % 2:
                result = mat_mult(result, M)
            M = mat_mult(M, M)
            p //= 2
        return result
    return mat_pow(adj, k)[u][v]
